const BG_IMAGE = "data:image/jpeg;base64,";

const stage = document.getElementById('stage');
const canvas = document.getElementById('baseCanvas');
const ctx = canvas.getContext('2d');
const handle = document.getElementById('nameHandle');
const nameLabel = document.getElementById('nameLabel');
const nameInput = document.getElementById('nameInput');
const fontSizeInput = document.getElementById('fontSize');
const fontColorInput = document.getElementById('fontColor');
const downloadBtn = document.getElementById('downloadBtn');
const btnPng = document.getElementById('btnPng');
const btnPdf = document.getElementById('btnPdf');

let img = new Image();
let exportFormat = 'png';
let selectedTitle = 'mr'; // 'mr' selected keeps ඔබතුමන්ට, strikes ඔබතුමීයට

// Precisely measured word positions (relative to full image, from source PDF render)
const WORD_MR = { x1: 0.1965, x2: 0.3410, y: 0.7565 }; // ඔබතුමන්ට
const WORD_MRS = { x1: 0.3823, x2: 0.5242, y: 0.7565 }; // ඔබතුමීයට

function drawStrike(word) {
    const pad = 0.006 * canvas.width;
    const x1 = word.x1 * canvas.width - pad;
    const x2 = word.x2 * canvas.width + pad;
    const y = word.y * canvas.height;
    ctx.save();
    ctx.strokeStyle = "#1a0505";
    ctx.lineWidth = Math.max(3, canvas.width * 0.0045);
    ctx.lineCap = "round";
    ctx.beginPath();
    ctx.moveTo(x1, y - canvas.height * 0.004);
    ctx.lineTo(x2, y + canvas.height * 0.004);
    ctx.stroke();
    ctx.restore();
}

// relative position (0-1) of handle center within the image
let relX = 0.5;
let relY = 0.79; // just below the "ඔබතුමන්ට / ඔබතුමීයට" line, adjustable by user
let fontSizeRel = 0.028; // relative to image width, so it scales properly on export

img.onload = () => {
    canvas.width = img.naturalWidth;
    canvas.height = img.naturalHeight;
    draw();
    positionHandle();
};
img.src = BG_IMAGE;

function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    drawStrike(selectedTitle === 'mr' ? WORD_MRS : WORD_MR);
}

function positionHandle() {
    const rect = stage.getBoundingClientRect();
    const w = rect.width;
    const h = rect.width * (img.naturalHeight / img.naturalWidth);
    const fontPx = Math.max(10, fontSizeRel * w * (fontSizeInput.value / 30));
    handle.style.fontSize = fontPx + "px";
    handle.style.color = fontColorInput.value;
    handle.style.fontWeight = "600";
    const text = nameInput.value.trim() || "Guest Name";
    nameLabel.textContent = text;

    // size the box to fit text
    handle.style.padding = "4px 10px";
    // must measure after applying font size
    requestAnimationFrame(() => {
        const bw = handle.offsetWidth;
        const bh = handle.offsetHeight;
        let left = relX * w - bw / 2;
        let top = relY * h - bh / 2;
        left = Math.max(0, Math.min(w - bw, left));
        top = Math.max(0, Math.min(h - bh, top));
        handle.style.left = left + "px";
        handle.style.top = top + "px";
        // update rel based on clamped position for consistency
        relX = (left + bw / 2) / w;
        relY = (top + bh / 2) / h;
    });
}

// dragging logic (mouse + touch)
let dragging = false;
let dragOffsetX = 0, dragOffsetY = 0;

function startDrag(clientX, clientY) {
    const hr = handle.getBoundingClientRect();
    dragOffsetX = clientX - hr.left;
    dragOffsetY = clientY - hr.top;
    dragging = true;
    handle.classList.add('dragging');
}
function moveDrag(clientX, clientY) {
    if (!dragging) return;
    const rect = stage.getBoundingClientRect();
    let left = clientX - rect.left - dragOffsetX;
    let top = clientY - rect.top - dragOffsetY;
    const bw = handle.offsetWidth, bh = handle.offsetHeight;
    left = Math.max(0, Math.min(rect.width - bw, left));
    top = Math.max(0, Math.min(rect.height - bh, top));
    handle.style.left = left + "px";
    handle.style.top = top + "px";
    relX = (left + bw / 2) / rect.width;
    relY = (top + bh / 2) / rect.height;
}
function endDrag() {
    dragging = false;
    handle.classList.remove('dragging');
}

handle.addEventListener('mousedown', e => { startDrag(e.clientX, e.clientY); e.preventDefault(); });
window.addEventListener('mousemove', e => moveDrag(e.clientX, e.clientY));
window.addEventListener('mouseup', endDrag);

handle.addEventListener('touchstart', e => {
    const t = e.touches[0];
    startDrag(t.clientX, t.clientY);
}, { passive: true });
window.addEventListener('touchmove', e => {
    if (!dragging) return;
    const t = e.touches[0];
    moveDrag(t.clientX, t.clientY);
    e.preventDefault();
}, { passive: false });
window.addEventListener('touchend', endDrag);

nameInput.addEventListener('input', positionHandle);
fontSizeInput.addEventListener('input', positionHandle);
fontColorInput.addEventListener('input', positionHandle);
window.addEventListener('resize', positionHandle);

const btnMr = document.getElementById('btnMr');
const btnMrs = document.getElementById('btnMrs');
btnMr.addEventListener('click', () => {
    selectedTitle = 'mr';
    btnMr.classList.add('active');
    btnMrs.classList.remove('active');
    draw();
});
btnMrs.addEventListener('click', () => {
    selectedTitle = 'mrs';
    btnMrs.classList.add('active');
    btnMr.classList.remove('active');
    draw();
});

btnPng.addEventListener('click', () => {
    exportFormat = 'png';
    btnPng.classList.add('active');
    btnPdf.classList.remove('active');
});
btnPdf.addEventListener('click', () => {
    exportFormat = 'pdf';
    btnPdf.classList.add('active');
    btnPng.classList.remove('active');
});

function renderFinalCanvas() {
    draw(); // redraw base image at full resolution
    const text = nameInput.value.trim() || "Guest Name";
    const fontPx = Math.max(10, fontSizeRel * canvas.width * (fontSizeInput.value / 30));
    ctx.font = "600 " + fontPx + "px -apple-system, 'Segoe UI', Roboto, Arial, sans-serif";
    ctx.fillStyle = fontColorInput.value;
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.shadowColor = "rgba(0,0,0,0.55)";
    ctx.shadowBlur = fontPx * 0.15;
    const x = relX * canvas.width;
    const y = relY * canvas.height;
    ctx.fillText(text, x, y);
    ctx.shadowBlur = 0;
}

downloadBtn.addEventListener('click', async () => {
    downloadBtn.disabled = true;
    downloadBtn.textContent = "Preparing...";
    await new Promise(r => setTimeout(r, 30));
    renderFinalCanvas();
    const safeName = (nameInput.value.trim() || "Guest").replace(/[^a-zA-Z0-9]+/g, '_');

    if (exportFormat === 'png') {
        canvas.toBlob(blob => {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `Break_of_Tribe_Invitation_${safeName}.png`;
            document.body.appendChild(a);
            a.click();
            a.remove();
            URL.revokeObjectURL(url);
            draw(); positionHandle();
            downloadBtn.disabled = false;
            downloadBtn.textContent = "Download Invitation";
        }, 'image/png');
    } else {
        const imgData = canvas.toDataURL('image/jpeg', 0.95);
        const { jsPDF } = window.jspdf;
        const pdfW = canvas.width;
        const pdfH = canvas.height;
        const pdf = new jsPDF({
            orientation: pdfW > pdfH ? 'l' : 'p',
            unit: 'px',
            format: [pdfW, pdfH]
        });
        pdf.addImage(imgData, 'JPEG', 0, 0, pdfW, pdfH);
        pdf.save(`Break_of_Tribe_Invitation_${safeName}.pdf`);
        draw(); positionHandle();
        downloadBtn.disabled = false;
        downloadBtn.textContent = "Download Invitation";
    }
});